import jwt
import json
from datetime import datetime, timezone
from typing import Optional, Union


def decode_jwt_unverified(token: str) -> dict:
    """
    Decode a JWT token WITHOUT signature verification.
    Useful for inspecting token contents during debugging.
    
    WARNING: Do not use this for authentication/authorization decisions.
    """
    try:
        header = jwt.get_unverified_header(token)
        payload = jwt.decode(token, options={"verify_signature": False}, algorithms=["HS256", "HS384", "HS512", "RS256", "RS384", "RS512", "ES256", "ES384", "ES512"])
        return {
            "header": header,
            "payload": payload,
            "is_valid": None,
            "validation_message": "Signature not verified (unverified decode)"
        }
    except jwt.exceptions.DecodeError as e:
        return {"error": f"Failed to decode token: {str(e)}"}
    except Exception as e:
        return {"error": f"Unexpected error: {str(e)}"}


def decode_jwt_verified(token: str, secret: str, algorithms: Optional[list] = None, audience: Optional[str] = None, issuer: Optional[str] = None) -> dict:
    """
    Decode and verify a JWT token with the provided secret/key.
    
    Args:
        token: The JWT token string.
        secret: The secret key or public key for verification.
        algorithms: List of allowed algorithms (default: ["HS256"]).
        audience: Expected audience claim.
        issuer: Expected issuer claim.
    
    Returns:
        Dictionary with header, payload, validity status, and any errors.
    """
    if algorithms is None:
        algorithms = ["HS256"]

    result = {
        "header": None,
        "payload": None,
        "is_valid": False,
        "validation_message": ""
    }

    try:
        result["header"] = jwt.get_unverified_header(token)
    except Exception as e:
        result["error"] = f"Failed to decode header: {str(e)}"
        return result

    decode_options = {}
    decode_kwargs = {
        "jwt": token,
        "key": secret,
        "algorithms": algorithms,
        "options": decode_options
    }
    if audience:
        decode_kwargs["audience"] = audience
    if issuer:
        decode_kwargs["issuer"] = issuer

    try:
        result["payload"] = jwt.decode(**decode_kwargs)
        result["is_valid"] = True
        result["validation_message"] = "Token is valid"
    except jwt.ExpiredSignatureError:
        result["is_valid"] = False
        result["validation_message"] = "Token has expired"
        result["payload"] = jwt.decode(token, secret, algorithms=algorithms, options={"verify_exp": False})
    except jwt.InvalidAudienceError:
        result["is_valid"] = False
        result["validation_message"] = "Invalid audience claim"
        result["payload"] = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
    except jwt.InvalidIssuerError:
        result["is_valid"] = False
        result["validation_message"] = "Invalid issuer claim"
        result["payload"] = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
    except jwt.InvalidSignatureError:
        result["is_valid"] = False
        result["validation_message"] = "Invalid signature"
        result["payload"] = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
    except jwt.DecodeError as e:
        result["is_valid"] = False
        result["validation_message"] = f"Token decode error: {str(e)}"
    except Exception as e:
        result["is_valid"] = False
        result["validation_message"] = f"Validation error: {str(e)}"

    return result


def inspect_token(token: str, secret: Optional[str] = None) -> None:
    """
    Pretty-print JWT token contents for debugging.
    If a secret is provided, also verifies the signature.
    
    Args:
        token: The JWT token string.
        secret: Optional secret key for signature verification.
    """
    print("=" * 60)
    print("JWT TOKEN INSPECTION")
    print("=" * 60)

    # Count segments
    parts = token.split(".")
    print(f"\nToken segments: {len(parts)}")
    if len(parts) != 3:
        print(f"WARNING: Expected 3 segments, got {len(parts)}. Token may be malformed.")

    # Decode without verification first
    decoded = decode_jwt_unverified(token)

    if "error" in decoded:
        print(f"\nERROR: {decoded['error']}")
        return

    # Header
    print(f"\n--- HEADER ---")
    print(json.dumps(decoded["header"], indent=2))

    # Payload
    print(f"\n--- PAYLOAD ---")
    payload = decoded["payload"]
    print(json.dumps(payload, indent=2, default=str))

    # Time-based claims analysis
    print(f"\n--- TIME CLAIMS ANALYSIS ---")
    now = datetime.now(timezone.utc)
    print(f"Current UTC time: {now.isoformat()}")

    time_claims = {
        "iat": "Issued At",
        "exp": "Expiration",
        "nbf": "Not Before"
    }

    for claim_key, claim_name in time_claims.items():
        if claim_key in payload:
            timestamp = payload[claim_key]
            claim_time = datetime.fromtimestamp(timestamp, tz=timezone.utc)
            delta = claim_time - now

            if claim_key == "exp":
                status = "EXPIRED" if delta.total_seconds() < 0 else "VALID"
                time_info = f"{'expired' if delta.total_seconds() < 0 else 'expires in'} {abs(delta)}"
            elif claim_key == "nbf":
                status = "ACTIVE" if delta.total_seconds() <= 0 else "NOT YET VALID"
                time_info = f"{'active since' if delta.total_seconds() <= 0 else 'becomes valid in'} {abs(delta)}"
            elif claim_key == "iat":
                time_info = f"issued {abs(delta)} ago"
                status = "OK"

            print(f"  {claim_name} ({claim_key}): {claim_time.isoformat()} [{status}] ({time_info})")
        else:
            print(f"  {claim_name} ({claim_key}): NOT PRESENT")

    # Common claims
    print(f"\n--- STANDARD CLAIMS ---")
    standard_claims = {
        "iss": "Issuer",
        "sub": "Subject",
        "aud": "Audience",
        "jti": "JWT ID"
    }
    for claim_key, claim_name in standard_claims.items():
        value = payload.get(claim_key, "NOT PRESENT")
        print(f"  {claim_name} ({claim_key}): {value}")

    # Custom claims
    all_standard = set(time_claims.keys()) | set(standard_claims.keys())
    custom_claims = {k: v for k, v in payload.items() if k not in all_standard}
    if custom_claims:
        print(f"\n--- CUSTOM CLAIMS ---")
        for key, value in custom_claims.items():
            print(f"  {key}: {json.dumps(value, default=str)}")

    # Verified decode if secret provided
    if secret:
        print(f"\n--- SIGNATURE VERIFICATION ---")
        alg = decoded["header"].get("alg", "HS256")
        verified = decode_jwt_verified(token, secret, algorithms=[alg])
        if verified["is_valid"]:
            print(f"  ✅ {verified['validation_message']}")
        else:
            print(f"  ❌ {verified['validation_message']}")
    else:
        print(f"\n--- SIGNATURE VERIFICATION ---")
        print("  ⚠️  No secret provided. Signature not verified.")

    print("\n" + "=" * 60)


def create_test_token(payload: Optional[dict] = None, secret: str = "test-secret", algorithm: str = "HS256", expires_in_seconds: int = 3600) -> str:
    """
    Create a test JWT token for debugging purposes.
    
    Args:
        payload: Custom payload dictionary.
        secret: Secret key for signing.
        algorithm: Signing algorithm.
        expires_in_seconds: Token expiration time in seconds.
    
    Returns:
        Encoded JWT token string.
    """
    now = datetime.now(timezone.utc)

    default_payload = {
        "sub": "user-123",
        "name": "Test User",
        "email": "test@example.com",
        "roles": ["user", "admin"],
        "iat": int(now.timestamp()),
        "exp": int(now.timestamp()) + expires_in_seconds,
        "iss": "debug-issuer",
        "aud": "debug-audience"
    }

    if payload:
        default_payload.update(payload)

    token = jwt.encode(default_payload, secret, algorithm=algorithm)
    return token


